insert into bouts (slug, fighter_a_id, fighter_b_id, weight_class, event_date, announced_at, headline, source, source_url, fighter_a_snapshot, fighter_b_snapshot, prompt) values ('anthony-joshua-vs-daniel-dubois', 'anthony-joshua', 'daniel-dubois', 'Heavyweight', NULL, NULL, 'Anthony Joshua vs Daniel Dubois', 'Sample matchup (illustrative, not an announced fight)', '', '{"capturedAt": "2026-06-29T22:57:36+00:00", "version": 1, "record": {"wins": 29, "losses": 4, "draws": null, "winsKo": 26, "winsDec": 3, "noContests": null}, "form": {"currentStreak": 1, "streakType": "KO", "last5": ["WKO", "LKO", "WKO", "WDEC", "WKO"], "kosInLastFive": 3, "_unverified": true}, "physical": {"age": 36, "dob": "1989-10-15", "heightInches": 78, "reachInches": 82, "stance": "Orthodox"}, "standing": {"titlesHeld": null, "rankings": {"wbc": null, "wbo": null, "ibf": null, "wba": null}}, "_meta": {"name": "Anthony Joshua", "realName": "Anthony Oluwafemi Olaseni Joshua", "nationality": null, "weightClasses": ["Heavyweight"], "hasWikipedia": true, "source": "https://en.wikipedia.org/wiki/Anthony_Joshua", "license": "Text CC BY-SA 4.0 — attribute Wikipedia on display.", "needsVerification": null, "formIsUnverified": true}}'::jsonb, '{"capturedAt": "2026-06-29T22:57:37+00:00", "version": 1, "record": {"wins": 23, "losses": 3, "draws": null, "winsKo": 22, "winsDec": 1, "noContests": null}, "form": {"currentStreak": 1, "streakType": "KO", "last5": ["WKO", "LKO", "WKO", "WKO", "WKO"], "kosInLastFive": 4, "_unverified": true}, "physical": {"age": 28, "dob": "1997-09-06", "heightInches": 77, "reachInches": 78, "stance": "Orthodox"}, "standing": {"titlesHeld": null, "rankings": {"wbc": null, "wbo": null, "ibf": null, "wba": null}}, "_meta": {"name": "Daniel Dubois", "realName": null, "nationality": null, "weightClasses": ["Heavyweight"], "hasWikipedia": true, "source": "https://en.wikipedia.org/wiki/Daniel_Dubois", "license": "Text CC BY-SA 4.0 — attribute Wikipedia on display.", "needsVerification": null, "formIsUnverified": true}}'::jsonb, '{"system": "You are a British boxing journalist writing fight-preview articles for BritBoxing (britboxing.co.uk). Tone: UK broadsheet boxing desk — factual, measured, no hype clichés (''all-action war'', ''fireworks''). PURPOSE: help the reader understand the two boxers and how the fight shapes up. This is editorial about the fighters, NOT a betting tip — do not discuss odds, who is the favourite, or give a win/method prediction. WRITE FOR VARIETY — this is important. Every preview must feel written from scratch for THIS fight, not poured into a template. Before writing, find the single most interesting angle this matchup''s data suggests — a huge experience gap, two unbeaten punchers, a reach mismatch, a veteran slowing down, a prospect''s step up — and build the piece around THAT. Vary your opening every time (never default to ''When a fight involves…''); vary the order you introduce the fighters; vary your section headings and how many sections you use; vary article length to fit how much the data supports. The structure below is a checklist of what to COVER, not a running order to follow. Two previews placed side by side should read as clearly different pieces. EMPHASIS: where one fighter is far more famous, weight the piece toward the lesser-known opponent — readers arrive knowing the big name. Where both are comparably known, treat them evenly. DATA DISCIPLINE: use ONLY the statistics provided in the prompt. Never invent records, rankings, dates, venues, quotes or biographical detail. If a stat is null/unknown, simply leave it out — never state that a figure is missing or unavailable. Use a stat only when it is genuinely informative (e.g. a clear reach or experience advantage); skip differences that are marginal. Form data marked unverified may be described softly (''recent outings suggest'') or omitted. Do not refer to yourself, to AI, or to how the article was produced. HOUSE STYLE — write like a person, not a model. Hard rules: NEVER use an em dash (—) or en dash (–); use commas, full stops or brackets and recast the sentence. Use straight quotes and apostrophes, not curly ones. Avoid these tell-tale constructions: ''not just X but Y'' and ''it''s not X, it''s Y''; ''not a … so much as …''; semicolon antithesis (''one has X; the other has Y''); rule-of-three lists for rhythm; and ending on a rhetorical ''the question is whether…''. Vary how each article closes. Avoid filler/marketing words (testament, stark reminder, delve, tapestry, landscape, realm, navigate, underscore, boasts, showcase, leverage, crucial, pivotal, robust) and hedging openers (That said, Ultimately, It''s worth noting, When it comes to, In a world where). Vary sentence length; let some sentences be short and plain. Return ONLY a JSON object with keys: title, slug, body, summary, tags. ''body'' is HTML (<p>, <h2>, <ul>) — no <html>/<head>. ''tags'' is an array of strings.", "user": "Write a fight-preview article for the following bout.\n\n## Bout\n- Matchup: Anthony Joshua vs Daniel Dubois\n- Announced via: Sample matchup (illustrative, not an announced fight) — headline: \"Anthony Joshua vs Daniel Dubois\"\n- Source link: \n- Event date: to be confirmed\n- Weight class (heaviest division both fighters share): Heavyweight\n\n## Fighter A — Anthony Joshua\n{\n  \"capturedAt\": \"2026-06-29T22:57:36+00:00\",\n  \"version\": 1,\n  \"record\": {\n    \"wins\": 29,\n    \"losses\": 4,\n    \"draws\": null,\n    \"winsKo\": 26,\n    \"winsDec\": 3,\n    \"noContests\": null\n  },\n  \"form\": {\n    \"currentStreak\": 1,\n    \"streakType\": \"KO\",\n    \"last5\": [\n      \"WKO\",\n      \"LKO\",\n      \"WKO\",\n      \"WDEC\",\n      \"WKO\"\n    ],\n    \"kosInLastFive\": 3,\n    \"_unverified\": true\n  },\n  \"physical\": {\n    \"age\": 36,\n    \"dob\": \"1989-10-15\",\n    \"heightInches\": 78,\n    \"reachInches\": 82,\n    \"stance\": \"Orthodox\"\n  },\n  \"standing\": {\n    \"titlesHeld\": null,\n    \"rankings\": {\n      \"wbc\": null,\n      \"wbo\": null,\n      \"ibf\": null,\n      \"wba\": null\n    }\n  },\n  \"_meta\": {\n    \"name\": \"Anthony Joshua\",\n    \"realName\": \"Anthony Oluwafemi Olaseni Joshua\",\n    \"nationality\": null,\n    \"weightClasses\": [\n      \"Heavyweight\"\n    ],\n    \"hasWikipedia\": true,\n    \"source\": \"https://en.wikipedia.org/wiki/Anthony_Joshua\",\n    \"license\": \"Text CC BY-SA 4.0 — attribute Wikipedia on display.\",\n    \"needsVerification\": null,\n    \"formIsUnverified\": true\n  }\n}\n\n## Fighter B — Daniel Dubois\n{\n  \"capturedAt\": \"2026-06-29T22:57:37+00:00\",\n  \"version\": 1,\n  \"record\": {\n    \"wins\": 23,\n    \"losses\": 3,\n    \"draws\": null,\n    \"winsKo\": 22,\n    \"winsDec\": 1,\n    \"noContests\": null\n  },\n  \"form\": {\n    \"currentStreak\": 1,\n    \"streakType\": \"KO\",\n    \"last5\": [\n      \"WKO\",\n      \"LKO\",\n      \"WKO\",\n      \"WKO\",\n      \"WKO\"\n    ],\n    \"kosInLastFive\": 4,\n    \"_unverified\": true\n  },\n  \"physical\": {\n    \"age\": 28,\n    \"dob\": \"1997-09-06\",\n    \"heightInches\": 77,\n    \"reachInches\": 78,\n    \"stance\": \"Orthodox\"\n  },\n  \"standing\": {\n    \"titlesHeld\": null,\n    \"rankings\": {\n      \"wbc\": null,\n      \"wbo\": null,\n      \"ibf\": null,\n      \"wba\": null\n    }\n  },\n  \"_meta\": {\n    \"name\": \"Daniel Dubois\",\n    \"realName\": null,\n    \"nationality\": null,\n    \"weightClasses\": [\n      \"Heavyweight\"\n    ],\n    \"hasWikipedia\": true,\n    \"source\": \"https://en.wikipedia.org/wiki/Daniel_Dubois\",\n    \"license\": \"Text CC BY-SA 4.0 — attribute Wikipedia on display.\",\n    \"needsVerification\": null,\n    \"formIsUnverified\": true\n  }\n}\n\n## What to cover (a checklist, NOT a running order — arrange it your own way for this fight)\n- A sense of each fighter: record, how they win (KO vs decision), recent outings.\n- The genuinely informative contrasts (a cl