n    \"stance\": \"Orthodox\"\n  },\n  \"standing\": {\n    \"titlesHeld\": null,\n    \"rankings\": {\n      \"wbc\": null,\n      \"wbo\": null,\n      \"ibf\": null,\n      \"wba\": null\n    }\n  },\n  \"_meta\": {\n    \"name\": \"Richard Riakporhe\",\n    \"realName\": null,\n    \"nationality\": null,\n    \"weightClasses\": [\n      \"Heavyweight\",\n      \"Cruiserweight (boxing)\"\n    ],\n    \"hasWikipedia\": true,\n    \"source\": \"https://en.wikipedia.org/wiki/Richard_Riakporhe\",\n    \"license\": \"Text CC BY-SA 4.0 — attribute Wikipedia on display.\",\n    \"needsVerification\": null,\n    \"formIsUnverified\": true\n  }\n}\n\n## Fighter B — Chris Billam-Smith\n{\n  \"capturedAt\": \"2026-06-29T22:57:40+00:00\",\n  \"version\": 1,\n  \"record\": {\n    \"wins\": 22,\n    \"losses\": 2,\n    \"draws\": null,\n    \"winsKo\": 14,\n    \"winsDec\": 8,\n    \"noContests\": null\n  },\n  \"form\": {\n    \"currentStreak\": 2,\n    \"streakType\": \"Decision\",\n    \"last5\": [\n      \"WDEC\",\n      \"WDEC\",\n      \"LDEC\",\n      \"WDEC\",\n      \"WDEC\"\n    ],\n    \"kosInLastFive\": 0,\n    \"_unverified\": true\n  },\n  \"physical\": {\n    \"age\": 35,\n    \"dob\": \"1990-08-02\",\n    \"heightInches\": 75,\n    \"reachInches\": 76,\n    \"stance\": \"Orthodox\"\n  },\n  \"standing\": {\n    \"titlesHeld\": null,\n    \"rankings\": {\n      \"wbc\": null,\n      \"wbo\": null,\n      \"ibf\": null,\n      \"wba\": null\n    }\n  },\n  \"_meta\": {\n    \"name\": \"Chris Billam-Smith\",\n    \"realName\": null,\n    \"nationality\": null,\n    \"weightClasses\": [\n      \"Cruiserweight (boxing)\"\n    ],\n    \"hasWikipedia\": true,\n    \"source\": \"https://en.wikipedia.org/wiki/Chris_Billam-Smith\",\n    \"license\": \"Text CC BY-SA 4.0 — attribute Wikipedia on display.\",\n    \"needsVerification\": null,\n    \"formIsUnverified\": true\n  }\n}\n\n## What to cover (a checklist, NOT a running order — arrange it your own way for this fight)\n- A sense of each fighter: record, how they win (KO vs decision), recent outings.\n- The genuinely informative contrasts (a clear experience, finishing-rate, reach\n  or age gap). Skip stats that are missing or marginal.\n- The stylistic questions the numbers raise — what each fighter must do.\nLead with whatever is most interesting about THIS matchup; vary your structure,\nheadings and opening from other previews. No odds, no favourite, no prediction.\n\nRemember: invent nothing; use only the JSON above. Omit anything you don''t have\ndata for — never mention that a figure is missing. Return the JSON object only.\n", "model": "claude-sonnet-4-6"}'::jsonb)
